const calculateMpMakeup = (inputs: UserInputs, method: CalculationMethod): PlatformResult => {
  const productCost = getNumber(inputs.productCost);
  const operationalCost = getNumber(inputs.operationalCost);
  const targetMargin = getNumber(inputs.targetMargin);
  const testPrice = getNumber(inputs.testPrice);

  const taxRateDecimal = inputs.isCNPJ ? getNumber(inputs.taxRate) / 100 : 0;
  // 5% Mercado Pago Fee + Tax
  const totalVariableRate = MP_MAKEUP_COMMISSION_RATE + taxRateDecimal;
  const totalFixedCosts = productCost + operationalCost + MP_MAKEUP_FIXED_FEE;

  let sellingPrice = 0;

  // OVERRIDE: If Force 100% Profit is checked
  // Logic: 100% ROI (Profit = Costs). Markup 100% basically.
  // Net Profit = Costs
  // Net Profit = Price - Costs - (Price * VarRate)
  // Costs = Price (1 - VarRate) - Costs
  // 2 * Costs = Price (1 - VarRate)
  // Price = (2 * Costs) / (1 - VarRate)

  if (inputs.mpMakeupForce100Percent) {
    const numerator = totalFixedCosts * 2;
    const denominator = 1 - totalVariableRate;

    if (denominator <= 0) {
        sellingPrice = 0;
    } else {
        sellingPrice = numerator / denominator;
    }
  } else {
    // Standard Calculation logic
    if (method === CalculationMethod.TARGET_MARGIN) {
        const marginDecimal = targetMargin / 100;
        const denominator = 1 - (totalVariableRate + marginDecimal);

        if (denominator <= 0) {
        sellingPrice = 0;
        } else {
        sellingPrice = totalFixedCosts / denominator;
        }
    } else {
        sellingPrice = testPrice;
    }
  }

  const commissionValue = sellingPrice * MP_MAKEUP_COMMISSION_RATE;
  const taxValue = sellingPrice * taxRateDecimal;
  const totalPlatformFees = commissionValue;
  const totalDeductions = totalPlatformFees + taxValue;
  const netProfit = sellingPrice - totalFixedCosts - totalDeductions;
  const netProfitMargin = sellingPrice > 0 ? (netProfit / sellingPrice) * 100 : 0;

  return {
    platformName: 'Loja Física MP Makeup',
    sellingPrice,
    netProfit,
    netProfitMargin,
    totalFixedCosts: totalFixedCosts,
    totalVariableCosts: totalPlatformFees,
    feesBreakdown: {
      commission: commissionValue, // Using commission field for MP Fee
      transactionFee: 0,
      fixedFee: MP_MAKEUP_FIXED_FEE,
      tax: taxValue,
    }
  };
};

