const calculateMpMakeup = (inputs: UserInputs, method: CalculationMethod): PlatformResult => {
  const productCost = getNumber(inputs.productCost);
  // We explicitly IGNORE operationalCost for MP Makeup as requested
  // const operationalCost = getNumber(inputs.operationalCost); 
  const targetMargin = getNumber(inputs.targetMargin);
  const testPrice = getNumber(inputs.testPrice);

  const taxRateDecimal = inputs.isCNPJ ? getNumber(inputs.taxRate) / 100 : 0;
  // 5% Mercado Pago Fee + Tax
  const totalVariableRate = MP_MAKEUP_COMMISSION_RATE + taxRateDecimal;

  // Costs = Product + Fixed Fee (0.50). Operational Cost is EXCLUDED.
  const totalFixedCosts = productCost + MP_MAKEUP_FIXED_FEE;

  let sellingPrice = 0;

  if (inputs.mpMakeupForce100Percent) {
    // CHECKED: Force 100% Markup (Profit = Cost)
    // Formula: Price = (2*Cost + FixedFee) / (1 - Rate)
    const numerator = (productCost * 2) + MP_MAKEUP_FIXED_FEE;
    const denominator = 1 - totalVariableRate;

    if (denominator <= 0) {
        sellingPrice = 0;
    } else {
        sellingPrice = numerator / denominator;
    }
  } else {
    // UNCHECKED:
    // If Target Margin: Treat input as MARKUP % (Profit on Cost), not Margin on Price.
    // This follows the "same rule" structure as the checked box (which is 100% markup).
    if (method === CalculationMethod.TARGET_MARGIN) {
        const marginDecimal = targetMargin / 100; // e.g., 0.30 for 30% markup
        // Formula derived from Price = Cost + (Cost*Margin) + Fixed + (Price*Rate)
        // Price = (Cost * (1 + Margin) + Fixed) / (1 - Rate)
        const numerator = (productCost * (1 + marginDecimal)) + MP_MAKEUP_FIXED_FEE;
        const denominator = 1 - totalVariableRate;

        if (denominator <= 0) {
            sellingPrice = 0;
        } else {
            sellingPrice = numerator / denominator;
        }
    } else {
        // Real Profit: User inputs price
        sellingPrice = testPrice;
    }
  }

  const commissionValue = sellingPrice * MP_MAKEUP_COMMISSION_RATE;
  const taxValue = sellingPrice * taxRateDecimal;
  const totalPlatformFees = commissionValue;
  const totalDeductions = totalPlatformFees + taxValue;
  const netProfit = sellingPrice - totalFixedCosts - totalDeductions;

  // MARGIN DISPLAY LOGIC UPDATE:
  // For MP Makeup, "Margin" is always calculated as MARKUP (Profit / Product Cost).
  // This satisfies: "margem de lucro muda de acordo com preço que eu colocar" (changes with price),
  // but follows the "rule" of being based on cost (like the 100% checked logic).
  let netProfitMargin = 0;
  if (productCost > 0) {
    netProfitMargin = (netProfit / productCost) * 100;
  }

  // If checked, force visual 100% just to be cleaner (math should match anyway)
  if (inputs.mpMakeupForce100Percent) {
    netProfitMargin = 100;
  }

  return {
    platformName: 'Loja Física MP Makeup',
    sellingPrice,
    netProfit,
    netProfitMargin,
    totalFixedCosts: totalFixedCosts,
    totalVariableCosts: totalPlatformFees,
    feesBreakdown: {
      commission: commissionValue, // Using commission field for MP Fee
      transactionFee: 0,
      fixedFee: MP_MAKEUP_FIXED_FEE,
      tax: taxValue,
    }
  };
};

export enum CalculationMethod {
  TARGET_MARGIN = 'TARGET_MARGIN',
  REAL_PROFIT = 'REAL_PROFIT'
}

export interface UserInputs {
  productCost: number | string; // CP
  operationalCost: number | string; // CFV
  targetMargin: number | string; // Margem Alvo % (0-100)
  testPrice: number | string; // Preço Teste
  isCNPJ: boolean; // Toggle CNPJ
  taxRate: number | string; // Alíquota de Imposto %
  mpMakeupForce100Percent?: boolean; // Checkbox para forçar 100% de lucro na MP Makeup
}

export interface PlatformResult {
  platformName: string;
  sellingPrice: number;
  netProfit: number;
  netProfitMargin: number;
  totalFixedCosts: number;
  totalVariableCosts: number;
  feesBreakdown: {
    commission: number;
    transactionFee: number;
    fixedFee: number;
    tax: number;
    affiliate?: number;
  };
}

export interface CalculationContext {
  mpMakeup: PlatformResult; // Only Physical Store remaining
}

import { UserInputs, PlatformResult, CalculationMethod } from '../types';

// Loja Física MP Makeup Constants
const MP_MAKEUP_COMMISSION_RATE = 0.05; // 5% Mercado Pago
const MP_MAKEUP_FIXED_FEE = 0.50; // Taxa fixa de 0.50 (Aluguel + Inter)

// Helper to safely convert input to number
const getNumber = (value: number | string): number => {
  if (typeof value === 'number') return value;
  if (!value) return 0;
  // Replace comma with dot just in case, though input type=number usually handles it or returns empty
  return parseFloat(value.toString().replace(',', '.')) || 0;
};

export const calculateResults = (inputs: UserInputs, method: CalculationMethod): { mpMakeup: PlatformResult } => {

  // Calculate MP Makeup (Physical Store)
  const mpMakeupResult = calculateMpMakeup(inputs, method);

  return { mpMakeup: mpMakeupResult };
};

const calculateMpMakeup = (inputs: UserInputs, method: CalculationMethod): PlatformResult => {
  const productCost = getNumber(inputs.productCost);
  // We explicitly IGNORE operationalCost for MP Makeup as requested previously
  // const operationalCost = getNumber(inputs.operationalCost); 
  const targetMargin = getNumber(inputs.targetMargin);
  const testPrice = getNumber(inputs.testPrice);

  const taxRateDecimal = inputs.isCNPJ ? getNumber(inputs.taxRate) / 100 : 0;
  // 5% Mercado Pago Fee + Tax
  const totalVariableRate = MP_MAKEUP_COMMISSION_RATE + taxRateDecimal;

  // Costs = Product + Fixed Fee (0.50). Operational Cost is EXCLUDED.
  const totalFixedCosts = productCost + MP_MAKEUP_FIXED_FEE;

  let sellingPrice = 0;

  if (inputs.mpMakeupForce100Percent) {
    // CHECKED: Force 100% Markup (Profit = Cost)
    // Formula: Price = (2*Cost + FixedFee) / (1 - Rate)
    const numerator = (productCost * 2) + MP_MAKEUP_FIXED_FEE;
    const denominator = 1 - totalVariableRate;

    if (denominator <= 0) {
        sellingPrice = 0;
    } else {
        sellingPrice = numerator / denominator;
    }
  } else {
    // UNCHECKED:
    // If Target Margin: Treat input as MARKUP % (Profit on Cost), not Margin on Price.
    // This follows the "same rule" structure as the checked box (which is 100% markup).
    if (method === CalculationMethod.TARGET_MARGIN) {
        const marginDecimal = targetMargin / 100; // e.g., 0.30 for 30% markup
        // Formula derived from Price = Cost + (Cost*Margin) + Fixed + (Price*Rate)
        // Price = (Cost * (1 + Margin) + Fixed) / (1 - Rate)
        const numerator = (productCost * (1 + marginDecimal)) + MP_MAKEUP_FIXED_FEE;
        const denominator = 1 - totalVariableRate;

        if (denominator <= 0) {
            sellingPrice = 0;
        } else {
            sellingPrice = numerator / denominator;
        }
    } else {
        // Real Profit: User inputs price
        sellingPrice = testPrice;
    }
  }

  const commissionValue = sellingPrice * MP_MAKEUP_COMMISSION_RATE;
  const taxValue = sellingPrice * taxRateDecimal;
  const totalPlatformFees = commissionValue;
  const totalDeductions = totalPlatformFees + taxValue;
  const netProfit = sellingPrice - totalFixedCosts - totalDeductions;

  // MARGIN DISPLAY LOGIC UPDATE:
  // For MP Makeup, "Margin" is always calculated as MARKUP (Profit / Product Cost).
  let netProfitMargin = 0;
  if (productCost > 0) {
    netProfitMargin = (netProfit / productCost) * 100;
  }

  // If checked, force visual 100% just to be cleaner (math should match anyway)
  if (inputs.mpMakeupForce100Percent) {
    netProfitMargin = 100;
  }

  return {
    platformName: 'Loja Física MP Makeup',
    sellingPrice,
    netProfit,
    netProfitMargin,
    totalFixedCosts: totalFixedCosts,
    totalVariableCosts: totalPlatformFees,
    feesBreakdown: {
      commission: commissionValue, // Using commission field for MP Fee
      transactionFee: 0,
      fixedFee: MP_MAKEUP_FIXED_FEE,
      tax: taxValue,
    }
  };
};

import { GoogleGenAI } from "@google/genai";
import { UserInputs, PlatformResult, CalculationMethod } from "../types";
import { formatCurrency, formatPercent } from "../utils/currency";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

const getNumber = (value: number | string): number => {
  if (typeof value === 'number') return value;
  if (!value) return 0;
  return parseFloat(value.toString().replace(',', '.')) || 0;
};

export const generatePricingAnalysis = async (
  inputs: UserInputs,
  mpMakeupResult: PlatformResult,
  method: CalculationMethod
): Promise<string> => {
  const client = getClient();
  if (!client) {
    return "API Key não configurada. Configure process.env.API_KEY para usar a IA.";
  }

  const methodText = method === CalculationMethod.TARGET_MARGIN 
    ? "Definição de Preço por Markup Alvo (Sobre Custo)" 
    : "Análise de Lucro Real";

  const productCost = getNumber(inputs.productCost);
  const operationalCost = getNumber(inputs.operationalCost);
  const targetMargin = getNumber(inputs.targetMargin);
  const testPrice = getNumber(inputs.testPrice);

  const prompt = `
    Atue como um estrategista financeiro de Varejo Físico e E-commerce.
    Analise os dados abaixo para a "Loja Física MP Makeup" e forneça uma resposta com EXCELENTE ESPAÇAMENTO e legibilidade.

    **Dados do Cenário (${methodText}):**
    - Custo Produto: ${formatCurrency(productCost)}
    ${method === CalculationMethod.TARGET_MARGIN ? `- Markup Alvo: ${targetMargin}%` : `- Preço Testado: ${formatCurrency(testPrice)}`}
    ${inputs.mpMakeupForce100Percent ? '- **Modo 100% Lucro Ativado**' : ''}

    **Resultados Apurados:**
    **Loja Física MP Makeup:** 
    - Preço Venda: ${formatCurrency(mpMakeupResult.sellingPrice)} 
    - Lucro Líquido: ${formatCurrency(mpMakeupResult.netProfit)} 
    - Markup Real: ${formatPercent(mpMakeupResult.netProfitMargin)}

    **Instruções de Resposta (Formato Visual):**

    ### 📊 Análise de Rentabilidade
    [Comente se o preço está competitivo e se a margem é saudável para loja física]

    ### 💡 Dica Estratégica
    [Uma sugestão tática para melhorar vendas ou margem neste produto]

    **Regras Importantes de Estilo:**
    - Use Markdown.
    - **IMPORTANTE:** Pule SEMPRE uma linha em branco entre cada item de lista e cada parágrafo. O texto deve ser arejado.
    - Seja conciso e direto.
    - Use emojis para guiar a leitura.
  `;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar a análise no momento.";
  } catch (error) {
    console.error("Erro ao chamar Gemini:", error);
    return "Erro ao conectar com a inteligência artificial. Tente novamente.";
  }
};

