import React from 'react';
import { PlatformResult } from '../types';
import { formatCurrency, formatPercent } from '../utils/currency';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface ResultCardProps {
  result: PlatformResult;
  colorTheme: 'orange' | 'black' | 'yellow' | 'blue' | 'pink';
  mpMakeupForce100Percent?: boolean;
  onMpMakeupForce100PercentChange?: (checked: boolean) => void;
}

const ResultCard: React.FC<ResultCardProps> = ({ 
  result, 
  colorTheme, 
  mpMakeupForce100Percent,
  onMpMakeupForce100PercentChange
}) => {

  const themeClasses = {
    orange: { border: 'border-orange-200', bg: 'bg-white', header: 'bg-orange-500', text: 'text-orange-600', fill: '#f97316' },
    black: { border: 'border-gray-200', bg: 'bg-white', header: 'bg-gray-900', text: 'text-gray-900', fill: '#111827' },
    yellow: { border: 'border-yellow-200', bg: 'bg-white', header: 'bg-yellow-400', text: 'text-yellow-700', fill: '#facc15' },
    blue: { border: 'border-slate-200', bg: 'bg-white', header: 'bg-slate-800', text: 'text-slate-800', fill: '#1e293b' },
    pink: { 
      border: 'border-pink-200', 
      bg: 'bg-white', 
      header: 'bg-gradient-to-r from-pink-500 to-rose-500', 
      text: 'text-pink-600', 
      fill: '#f472b6' 
    }
  };

  const currentTheme = themeClasses[colorTheme];

  // Calculate total money paid to the platform (Now only Variable Costs + Fixed Fee + Affiliate)
  const totalFees = result.totalVariableCosts + 
                    result.feesBreakdown.fixedFee + 
                    (result.feesBreakdown.affiliate || 0);

  // Calculate total cost (Product + All Fees)
  // totalFixedCosts in calculation is Product + Fixed Fee. 
  // We want just Product here for the breakdown display.
  const productCostOnly = result.totalFixedCosts - result.feesBreakdown.fixedFee;
  const totalSaleCost = productCostOnly + totalFees;

  const chartData = [
    { name: 'Custo Produto', value: productCostOnly, color: '#9CA3AF' },
    { name: 'Taxas & Encargos', value: totalFees, color: '#EF4444' },
    { name: 'Lucro Líquido', value: result.netProfit > 0 ? result.netProfit : 0, color: '#10B981' },
  ];

  // Custom text color for ML header because yellow background is light
  const headerTextColor = colorTheme === 'yellow' ? 'text-gray-900' : 'text-white';

  return (
    <div className={`rounded-xl shadow-lg overflow-hidden border ${currentTheme.border} ${currentTheme.bg} flex flex-col h-full`}>
      <div className={`${currentTheme.header} ${headerTextColor} p-4 flex justify-between items-center`}>
        <h3 className="font-bold text-lg">{result.platformName}</h3>
      </div>

      <div className="p-6 flex-1 flex flex-col">

        {/* Controls Container */}
        <div className="mb-4">
            {/* MP Makeup Force 100% Profit Section */}
            {colorTheme === 'pink' && (
                <div className="bg-pink-50 p-3 rounded-lg border border-pink-100">
                    <label className="flex items-center space-x-3 cursor-pointer">
                        <input 
                        type="checkbox" 
                        checked={mpMakeupForce100Percent || false} 
                        onChange={(e) => onMpMakeupForce100PercentChange?.(e.target.checked)}
                        className="w-5 h-5 text-pink-600 rounded border-gray-300 focus:ring-pink-500 cursor-pointer accent-pink-500"
                        />
                        <span className="text-sm font-bold text-pink-900">Aplicar 100% de Lucro</span>
                    </label>
                    <p className="text-[10px] text-pink-500 mt-1.5 pl-8 leading-tight">
                        Calcula o preço para dobrar o investimento (ROI 100% sobre custo).
                    </p>
                </div>
            )}
        </div>

        <div className="mb-6 text-center">
          <p className="text-sm text-gray-500 mb-1">Preço de Venda Final</p>
          <div className={`text-5xl font-bold ${currentTheme.text} tracking-tight`}>
            {formatCurrency(result.sellingPrice)}
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-6">
           <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase tracking-wide mb-1">Lucro (R$)</p>
              <p className="text-3xl font-bold text-emerald-600">{formatCurrency(result.netProfit)}</p>
           </div>
           <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase tracking-wide mb-1">Markup</p>
              <p className="text-3xl font-bold text-emerald-600">{formatPercent(result.netProfitMargin)}</p>
           </div>
        </div>

        <div className="mb-6 h-48 w-full relative">
           <ResponsiveContainer width="100%" height="100%">
             <PieChart>
               <Pie
                 data={chartData}
                 cx="50%"
                 cy="50%"
                 innerRadius={60}
                 outerRadius={80}
                 paddingAngle={2}
                 dataKey="value"
               >
                 {chartData.map((entry, index) => (
                   <Cell key={`cell-${index}`} fill={entry.color} />
                 ))}
               </Pie>
               <Tooltip formatter={(value: number) => formatCurrency(value)} />
             </PieChart>
           </ResponsiveContainer>
           <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
             <span className="text-xs text-gray-400 font-medium">Composição</span>
           </div>
        </div>

        <div className="space-y-3 text-sm border-t border-gray-100 pt-5 mt-auto">
          <div className="flex justify-between">
             <span className="text-gray-500">Custo Produto:</span>
            <span className="font-medium text-gray-700">{formatCurrency(productCostOnly)}</span>
          </div>
          <div className="flex justify-between">
             <span className="text-gray-500">Comissão (MP):</span>
             <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.commission)}</span>
          </div>
           <div className="flex justify-between">
              <span className="text-gray-500">Taxa Fixa (Aluguel/Inter):</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.fixedFee)}</span>
            </div>

            <div className="flex justify-between font-semibold bg-gray-50 rounded px-2 py-2 -mx-2 mt-2">
               <span className="text-gray-700">Taxas Totais:</span>
               <span className="text-red-600">-{formatCurrency(totalFees)}</span>
            </div>

           <div className="flex justify-between font-bold text-gray-800 pt-2 border-t border-gray-100 mt-2">
              <span>Custo Total da Venda:</span>
              <span>-{formatCurrency(totalSaleCost)}</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default ResultCard;

