import React, { useState, useEffect } from 'react';
import { formatCurrency } from '../utils/currency';

interface UnitCostCalculatorProps {
  onApplyCost: (cost: number) => void;
}

const UnitCostCalculator: React.FC<UnitCostCalculatorProps> = ({ onApplyCost }) => {
  const [boxCost, setBoxCost] = useState<string>('');
  const [quantity, setQuantity] = useState<string>('');
  const [unitCost, setUnitCost] = useState<number>(0);

  const parseInput = (val: string) => parseFloat(val.replace(',', '.')) || 0;

  useEffect(() => {
    const c = parseInput(boxCost);
    const q = parseInput(quantity);
    if (c > 0 && q > 0) {
      setUnitCost(c / q);
    } else {
      setUnitCost(0);
    }
  }, [boxCost, quantity]);

  const handleApply = () => {
    if (unitCost > 0) {
      onApplyCost(unitCost);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-md border border-pink-100 overflow-hidden h-full flex flex-col">
      <div className="bg-gradient-to-r from-pink-50 to-rose-50 px-5 py-3 border-b border-pink-100 flex items-center justify-between shrink-0">
        <h3 className="font-bold text-gray-800 text-base">Calculadora de Box</h3>
        <span className="text-[10px] bg-pink-100 text-pink-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-wide">Auxiliar</span>
      </div>

      <div className="p-5 flex flex-col flex-1 gap-5 overflow-y-auto">
        <div className="space-y-4">
          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1.5">Custo do Box (R$)</label>
            <input
              type="number"
              inputMode="decimal"
              placeholder="0,00"
              value={boxCost}
              onChange={(e) => setBoxCost(e.target.value)}
              className="w-full px-3 py-2 text-base border border-gray-300 rounded-lg focus:ring-2 focus:ring-pink-500 outline-none text-gray-900"
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1.5">Quantidade de Itens</label>
            <input
              type="number"
              inputMode="numeric"
              placeholder="0"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              className="w-full px-3 py-2 text-base border border-gray-300 rounded-lg focus:ring-2 focus:ring-pink-500 outline-none text-gray-900"
            />
          </div>
        </div>

        <div className="bg-gray-50 rounded-xl p-4 text-center border border-gray-100 mt-auto mb-auto">
          <p className="text-xs text-gray-500 font-bold uppercase tracking-wide mb-1">Custo Unitário</p>
          <p className="text-4xl font-bold text-gray-800">{formatCurrency(unitCost)}</p>
        </div>

        <button
          onClick={handleApply}
          disabled={unitCost <= 0}
          className={`w-full py-3 px-4 rounded-lg font-bold text-sm transition-all flex items-center justify-center gap-2 shrink-0 shadow-sm hover:shadow-md ${
            unitCost > 0
              ? 'bg-pink-600 hover:bg-pink-700 text-white'
              : 'bg-gray-100 text-gray-400 cursor-not-allowed'
          }`}
        >
          <span>Aplicar Custo no Principal</span>
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12h15m0 0l-6.75-6.75M19.5 12l-6.75 6.75" />
          </svg>
        </button>
      </div>
    </div>
  );
};

